import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import Cronometro from '../components/Cronometro';

function NovaOs() {
    const navigate = useNavigate();
    const [clientes, setClientes] = useState([]);
    const [categorias, setCategorias] = useState([]);
    const [form, setForm] = useState({
        cliente_id: '',
        categoria_id: '',
        numero_os: '',
        equipamento: '',
        modelo: '',
        imei: '',
        defeito: '',
        tipo_atendimento: 'presencial',
        estimativa_horas: '',
        preco_final: ''
    });
    const [erro, setErro] = useState('');
    const [sucesso, setSucesso] = useState('');
    const [osCriadaId, setOsCriadaId] = useState(null);

    useEffect(() => {
        const carregarDados = async () => {
            try {
                const clientesRes = await api.get('/clientes');
                setClientes(clientesRes.data);
                const catRes = await api.get('/clientes/categorias');
                setCategorias(catRes.data);
                // Gerar número da OS automaticamente (baseado em timestamp)
                const data = new Date();
                const ano = data.getFullYear();
                const mes = String(data.getMonth() + 1).padStart(2, '0');
                const dia = String(data.getDate()).padStart(2, '0');
                const aleatorio = Math.floor(Math.random() * 1000);
                const numeroOs = `${ano}${mes}${dia}-${aleatorio}`;
                setForm(prev => ({ ...prev, numero_os: numeroOs }));
            } catch (error) {
                console.error(error);
            }
        };
        carregarDados();
    }, []);

    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };

    const handleCategoriaChange = (e) => {
        const catId = e.target.value;
        const categoria = categorias.find(c => c.id === parseInt(catId));
        setForm({
            ...form,
            categoria_id: catId,
            preco_final: categoria ? categoria.preco_sugerido : '',
            estimativa_horas: categoria && categoria.tempo_estimado_minutos ? (categoria.tempo_estimado_minutos / 60).toFixed(2) : ''
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setErro('');
        setSucesso('');
        try {
            // Verificar se cliente existe
            if (!form.cliente_id) {
                setErro('Selecione um cliente');
                return;
            }
            const response = await api.post('/os', form);
            setOsCriadaId(response.data.id);
            setSucesso('Ordem de Serviço criada com sucesso!');
        } catch (error) {
            console.error(error);
            setErro('Erro ao criar OS. Verifique os dados.');
        }
    };

    if (osCriadaId) {
        return (
            <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
                <h2>OS criada com sucesso!</h2>
                <p>Número da OS: {form.numero_os}</p>
                <Cronometro osId={osCriadaId} />
                <div style={{ marginTop: '20px' }}>
                    <button onClick={() => navigate('/')} style={{ padding: '10px 20px', marginRight: '10px' }}>Ir para Home</button>
                    <button onClick={() => window.location.reload()} style={{ padding: '10px 20px' }}>Nova OS</button>
                </div>
            </div>
        );
    }

    return (
        <div style={{ maxWidth: '800px', margin: '0 auto', padding: '20px' }}>
            <h2>Nova Ordem de Serviço</h2>
            {erro && <div style={{ color: 'red', marginBottom: '10px' }}>{erro}</div>}
            {sucesso && <div style={{ color: 'green', marginBottom: '10px' }}>{sucesso}</div>}
            <form onSubmit={handleSubmit}>
                <div style={{ marginBottom: '15px' }}>
                    <label>Cliente *</label><br />
                    <select name="cliente_id" value={form.cliente_id} onChange={handleChange} required style={{ width: '100%', padding: '8px' }}>
                        <option value="">Selecione</option>
                        {clientes.map(c => <option key={c.id} value={c.id}>{c.nome} - {c.telefone}</option>)}
                    </select>
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Categoria (serviço)</label><br />
                    <select name="categoria_id" value={form.categoria_id} onChange={handleCategoriaChange} style={{ width: '100%', padding: '8px' }}>
                        <option value="">Selecione</option>
                        {categorias.map(c => <option key={c.id} value={c.id}>{c.nome} - R$ {c.preco_sugerido}</option>)}
                    </select>
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Número da OS *</label><br />
                    <input type="text" name="numero_os" value={form.numero_os} onChange={handleChange} required style={{ width: '100%', padding: '8px' }} readOnly />
                    <small>Automático, pode editar se necessário</small>
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Equipamento</label><br />
                    <input type="text" name="equipamento" value={form.equipamento} onChange={handleChange} style={{ width: '100%', padding: '8px' }} placeholder="Ex: PC, Notebook, iPhone 12" />
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Modelo</label><br />
                    <input type="text" name="modelo" value={form.modelo} onChange={handleChange} style={{ width: '100%', padding: '8px' }} />
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>IMEI (para celular)</label><br />
                    <input type="text" name="imei" value={form.imei} onChange={handleChange} style={{ width: '100%', padding: '8px' }} />
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Defeito relatado</label><br />
                    <textarea name="defeito" value={form.defeito} onChange={handleChange} rows="3" style={{ width: '100%', padding: '8px' }}></textarea>
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Tipo de atendimento</label><br />
                    <select name="tipo_atendimento" value={form.tipo_atendimento} onChange={handleChange} style={{ width: '100%', padding: '8px' }}>
                        <option value="presencial">Presencial</option>
                        <option value="remoto">Remoto</option>
                    </select>
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Estimativa de horas (opcional)</label><br />
                    <input type="number" step="0.5" name="estimativa_horas" value={form.estimativa_horas} onChange={handleChange} style={{ width: '100%', padding: '8px' }} />
                </div>
                <div style={{ marginBottom: '15px' }}>
                    <label>Preço final (R$)</label><br />
                    <input type="number" step="0.01" name="preco_final" value={form.preco_final} onChange={handleChange} style={{ width: '100%', padding: '8px' }} />
                </div>
                <button type="submit" style={{ padding: '10px 20px', background: '#007bff', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Criar OS</button>
                <button type="button" onClick={() => navigate('/')} style={{ marginLeft: '10px', padding: '10px 20px', background: '#6c757d', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}>Cancelar</button>
            </form>
        </div>
    );
}

export default NovaOs;
